fun solve(nums: Array<Long>): Long {
    val n = nums.size
    val dist = LongArray(n).apply { fill(0L) }
    val visited = BooleanArray(n).apply { fill(false) }
    val queue = ArrayDeque<Int>().apply { add(0) }
    dist[0] = 0L

    while (queue.isNotEmpty()) {
        val i = queue.removeFirst()
        visited[i] = true

        // Move to adjacent cells
        for (j in listOf(i - 1, i + 1)) {
            if (j in 0..n - 1 && !visited[j]) {
                dist[j] = dist[i] + 1
                queue.add(j)
            }
        }

        // Prime teleport
        if (isPrime(nums[i])) {
            val p = nums[i]
            for (j in 0..n - 1) {
                if (j != i && nums[j] % p == 0 && !visited[j]) {
                    dist[j] = min(dist[j], dist[i] + 1)
                    queue.add(j)
                }
            }
        }
    }

    return dist[n - 1]
}

fun isPrime(num: Long): Boolean {
    if (num < 2) return false
    for (i in 2..Math.sqrt(num.toDouble()).toLong()) {
        if (num % i == 0) return false
    }
    return true
}
